module RefModule (
    input  A1  ,
    input  A2  ,
    input  B1  ,
    input  C1  ,
    output X   
);

  wire temp1_(A1 & A2) | (~A1 & B1) = (A1 & A2) | (~A1 & B1);
  wire temp2_(~A1 & ~B1 & C1) = (~A1 & ~B1 & C1);
  assign X = temp1_(A1 & A2) | (~A1 & B1) | temp2_(~A1 & ~B1 & C1);

endmodule
